_COMPARISON_OPERATORS = {"=", "!=", "<>", "<", "<=", ">", ">="}
_ADDITIVE_OPERATORS = {"+", "-", "||"}
_MULTIPLICATIVE_OPERATORS = {"*", "/", "%"}
_STATEMENT_STARTS = {
    TokenType.SELECT,
    TokenType.INSERT,
    TokenType.UPDATE,
    TokenType.DELETE,
    TokenType.CREATE,
    TokenType.DROP,
}
