class Parser:
    """Parse lexer tokens into QueryWeave AST nodes."""

    def __init__(self, source: str | Lexer | TokenStream | list[Token]) -> None:
        if isinstance(source, str):
            self.tokens = TokenStream(Lexer(source).tokenize())
        elif isinstance(source, Lexer):
            self.tokens = TokenStream(source.tokenize())
        elif isinstance(source, TokenStream):
            self.tokens = source
        else:
            self.tokens = TokenStream(source)

    def parse_statement(self) -> Statement:
        """Parse a single complete SQL statement."""
        statement = self._parse_statement_body()
        self._match(TokenType.SEMICOLON)
        if not self._check(TokenType.EOF):
            self._error_current("Unexpected token after statement")
        return statement

    def _parse_statement_body(self) -> Statement:
        if self._check(TokenType.SELECT):
            return self._parse_select_or_union()
        if self._check(TokenType.INSERT):
            return self._parse_insert()
        if self._check(TokenType.UPDATE):
            return self._parse_update()
        if self._check(TokenType.DELETE):
            return self._parse_delete()
        if self._check(TokenType.CREATE):
            return self._parse_create_table()
        if self._check(TokenType.DROP):
            return self._parse_drop_table()
        self._error_current("Expected a SQL statement")

    def _parse_select_or_union(self) -> SelectStmt | UnionStmt:
        left = self._parse_select()
        if not self._match(TokenType.UNION):
            return left
        all_ = self._match(TokenType.ALL) is not None
        right = self._parse_select_or_union()
        return UnionStmt(left=left, right=right, all=all_)

    def _parse_select(self) -> SelectStmt:
        self._expect(TokenType.SELECT)
        distinct = self._match(TokenType.DISTINCT) is not None
        columns = self._parse_select_list()

        from_table = None
        joins: list[JoinClause] = []
        if self._match(TokenType.FROM):
            from_table = self._parse_table_ref()
            joins = self._parse_joins()

        where = None
        if self._match(TokenType.WHERE):
            where = WhereClause(self._parse_expression())

        group_by = None
        if self._match_group_by():
            group_by = GroupByClause(self._parse_expression_list())

        having = None
        if self._match(TokenType.HAVING):
            having = HavingClause(self._parse_expression())

        order_by = None
        if self._match_order_by():
            order_by = OrderByClause(self._parse_order_by_items())

        limit = None
        if self._match(TokenType.LIMIT):
            limit = LimitClause(limit=self._parse_integer_literal("LIMIT"))

        if self._match(TokenType.OFFSET):
            offset = self._parse_integer_literal("OFFSET")
            if limit is None:
                self._error_current("OFFSET requires LIMIT")
            limit.offset = offset

        return SelectStmt(
            columns=columns,
            from_table=from_table,
            joins=joins,
            where=where,
            group_by=group_by,
            having=having,
            order_by=order_by,
            limit=limit,
            distinct=distinct,
        )

    def _parse_select_list(self) -> list[Expression]:
        if self._check(TokenType.FROM, TokenType.EOF, TokenType.SEMICOLON):
            self._error_current("SELECT requires at least one expression")

        columns = []
        while True:
            expr = self._parse_expression()
            alias = self._parse_optional_alias()
            if alias is not None:
                expr = AliasExpr(expr=expr, alias=alias)
            columns.append(expr)
            if not self._match(TokenType.COMMA):
                break
        return columns

    def _parse_joins(self) -> list[JoinClause]:
        joins: list[JoinClause] = []
        while True:
            join_type = "INNER"
            if self._match(TokenType.LEFT):
                join_type = "LEFT"
                self._match(TokenType.OUTER)
            elif self._match(TokenType.RIGHT):
                join_type = "RIGHT"
                self._match(TokenType.OUTER)
            elif self._match(TokenType.FULL):
                join_type = "FULL"
                self._match(TokenType.OUTER)
            elif self._match(TokenType.INNER):
                join_type = "INNER"
            elif self._match(TokenType.CROSS):
                join_type = "CROSS"
            elif not self._check(TokenType.JOIN):
                break

            self._expect(TokenType.JOIN)
            table = self._parse_table_ref()
            condition = None
            if self._match(TokenType.ON):
                condition = self._parse_expression()
            elif join_type != "CROSS":
                self._error_current(f"{join_type} JOIN requires ON condition")
            joins.append(JoinClause(join_type=join_type, table=table, condition=condition))
        return joins

    def _parse_insert(self) -> InsertStmt:
        self._expect(TokenType.INSERT)
        self._expect(TokenType.INTO)
        table = self._parse_table_ref(allow_alias=False)
        columns: list[str] = []
        if self._match(TokenType.LPAREN):
            columns = self._parse_identifier_list()
            self._expect(TokenType.RPAREN)

        values: list[list[Expression]] = []
        select = None
        if self._match(TokenType.VALUES):
            while True:
                self._expect(TokenType.LPAREN)
                values.append(self._parse_expression_list())
                self._expect(TokenType.RPAREN)
                if not self._match(TokenType.COMMA):
                    break
        elif self._check(TokenType.SELECT):
            parsed = self._parse_select_or_union()
            if not isinstance(parsed, SelectStmt):
                self._error_current("INSERT ... SELECT does not support UNION")
            select = parsed
        else:
            self._error_current("Expected VALUES or SELECT in INSERT")

        return InsertStmt(table=table, columns=columns, values=values, select=select)

    def _parse_update(self) -> UpdateStmt:
        self._expect(TokenType.UPDATE)
        table = self._parse_table_ref(allow_alias=False)
        self._expect(TokenType.SET)

        assignments = []
        while True:
            column = self._parse_identifier_path()
            self._expect_operator("=")
            assignments.append(Assignment(column=column, value=self._parse_expression()))
            if not self._match(TokenType.COMMA):
                break

        where = None
        if self._match(TokenType.WHERE):
            where = WhereClause(self._parse_expression())
        return UpdateStmt(table=table, assignments=assignments, where=where)

    def _parse_delete(self) -> DeleteStmt:
        self._expect(TokenType.DELETE)
        self._expect(TokenType.FROM)
        table = self._parse_table_ref(allow_alias=False)
        where = None
        if self._match(TokenType.WHERE):
            where = WhereClause(self._parse_expression())
        return DeleteStmt(table=table, where=where)

    def _parse_create_table(self) -> CreateTableStmt:
        self._expect(TokenType.CREATE)
        self._expect(TokenType.TABLE)
        if_not_exists = False
        if self._match_identifier("IF"):
            self._expect(TokenType.NOT)
            self._expect(TokenType.EXISTS)
            if_not_exists = True

        table = self._parse_table_ref(allow_alias=False)
        self._expect(TokenType.LPAREN)
        columns: list[ColumnDef] = []
        if not self._check(TokenType.RPAREN):
            while True:
                columns.append(self._parse_column_def())
                if not self._match(TokenType.COMMA):
                    break
        self._expect(TokenType.RPAREN)
        return CreateTableStmt(table=table, columns=columns, if_not_exists=if_not_exists)

    def _parse_column_def(self) -> ColumnDef:
        name = self._parse_identifier()
        data_type = self._parse_data_type()
        nullable = True
        primary_key = False
        default = None

        while not self._check(TokenType.COMMA, TokenType.RPAREN, TokenType.EOF):
            if self._match(TokenType.NOT):
                self._expect(TokenType.NULL)
                nullable = False
            elif self._match(TokenType.NULL):
                nullable = True
            elif self._match_identifier("PRIMARY"):
                self._expect_identifier("KEY")
                primary_key = True
                nullable = False
            elif self._match_identifier("DEFAULT"):
                default = self._parse_expression()
            else:
                self._error_current("Expected column constraint")

        return ColumnDef(
            name=name,
            data_type=data_type,
            nullable=nullable,
            primary_key=primary_key,
            default=default,
        )

    def _parse_drop_table(self) -> DropTableStmt:
        self._expect(TokenType.DROP)
        self._expect(TokenType.TABLE)
        if_exists = False
        if self._match_identifier("IF"):
            self._expect(TokenType.EXISTS)
            if_exists = True
        table = self._parse_table_ref(allow_alias=False)
        return DropTableStmt(table=table, if_exists=if_exists)

    def _parse_expression(self) -> Expression:
        return self._parse_or()

    def _parse_or(self) -> Expression:
        expr = self._parse_and()
        while self._match(TokenType.OR):
            expr = BinaryExpr(left=expr, operator="OR", right=self._parse_and())
        return expr

    def _parse_and(self) -> Expression:
        expr = self._parse_not()
        while self._match(TokenType.AND):
            expr = BinaryExpr(left=expr, operator="AND", right=self._parse_not())
        return expr

    def _parse_not(self) -> Expression:
        if self._match(TokenType.NOT):
            return UnaryExpr(operator="NOT", operand=self._parse_not())
        return self._parse_comparison()

    def _parse_comparison(self) -> Expression:
        expr = self._parse_additive()

        while True:
            if self._match(TokenType.IS):
                negated = self._match(TokenType.NOT) is not None
                self._expect(TokenType.NULL)
                expr = IsNullExpr(expr=expr, negated=negated)
            elif self._match(TokenType.IN):
                expr = self._finish_in_expr(expr, negated=False)
            elif self._match(TokenType.BETWEEN):
                expr = self._finish_between_expr(expr, negated=False)
            elif self._match(TokenType.LIKE):
                expr = LikeExpr(expr=expr, pattern=self._parse_additive(), negated=False)
            elif self._check(TokenType.NOT):
                pos = self.tokens.save()
                self._advance()
                if self._match(TokenType.IN):
                    expr = self._finish_in_expr(expr, negated=True)
                elif self._match(TokenType.BETWEEN):
                    expr = self._finish_between_expr(expr, negated=True)
                elif self._match(TokenType.LIKE):
                    expr = LikeExpr(expr=expr, pattern=self._parse_additive(), negated=True)
                else:
                    self.tokens.restore(pos)
                    break
            elif self._check(TokenType.OPERATOR) and self._current().value in _COMPARISON_OPERATORS:
                operator = self._advance().value
                expr = BinaryExpr(left=expr, operator=operator, right=self._parse_additive())
            else:
                break
        return expr

    def _finish_in_expr(self, expr: Expression, negated: bool) -> InExpr:
        self._expect(TokenType.LPAREN)
        if self._check(TokenType.SELECT):
            values = SubqueryExpr(self._parse_select())
        else:
            values = []
            if not self._check(TokenType.RPAREN):
                values = self._parse_expression_list()
        self._expect(TokenType.RPAREN)
        return InExpr(expr=expr, values=values, negated=negated)

    def _finish_between_expr(self, expr: Expression, negated: bool) -> BetweenExpr:
        low = self._parse_additive()
        self._expect(TokenType.AND)
        high = self._parse_additive()
        return BetweenExpr(expr=expr, low=low, high=high, negated=negated)

    def _parse_additive(self) -> Expression:
        expr = self._parse_multiplicative()
        while self._check(TokenType.OPERATOR) and self._current().value in _ADDITIVE_OPERATORS:
            operator = self._advance().value
            expr = BinaryExpr(left=expr, operator=operator, right=self._parse_multiplicative())
        return expr

    def _parse_multiplicative(self) -> Expression:
        expr = self._parse_unary()
        while (
            (self._check(TokenType.OPERATOR) and self._current().value in _MULTIPLICATIVE_OPERATORS)
            or self._check(TokenType.STAR)
        ):
            operator = "*" if self._check(TokenType.STAR) else self._current().value
            self._advance()
            expr = BinaryExpr(left=expr, operator=operator, right=self._parse_unary())
        return expr

    def _parse_unary(self) -> Expression:
        if self._check(TokenType.OPERATOR) and self._current().value in {"+", "-", "!"}:
            operator = self._advance().value
            return UnaryExpr(operator=operator, operand=self._parse_unary())
        return self._parse_postfix()

    def _parse_postfix(self) -> Expression:
        expr = self._parse_primary()
        while self._match(TokenType.OVER):
            if not isinstance(expr, (FunctionCall, AggregateExpr)):
                self._error_current("OVER can only follow a function call")
            expr = self._finish_window_expr(expr)
        return expr

    def _parse_primary(self) -> Expression:
        if token := self._match(TokenType.NUMBER):
            return LiteralExpr(value=int(token.value), literal_type="integer")
        if token := self._match(TokenType.FLOAT):
            return LiteralExpr(value=float(token.value), literal_type="float")
        if token := self._match(TokenType.STRING):
            return LiteralExpr(value=token.value, literal_type="string")
        if self._match(TokenType.TRUE):
            return LiteralExpr(value=True, literal_type="boolean")
        if self._match(TokenType.FALSE):
            return LiteralExpr(value=False, literal_type="boolean")
        if self._match(TokenType.NULL):
            return LiteralExpr(value=None, literal_type="null")
        if self._match(TokenType.STAR):
            return StarExpr()
        if self._check(TokenType.IDENTIFIER):
            return self._parse_identifier_expression()
        if self._check(TokenType.EXISTS):
            return self._parse_exists()
        if self._check(TokenType.CASE):
            return self._parse_case()
        if self._match(TokenType.LPAREN):
            if self._check(TokenType.SELECT):
                query = self._parse_select()
                self._expect(TokenType.RPAREN)
                return SubqueryExpr(query=query)
            expr = self._parse_expression()
            self._expect(TokenType.RPAREN)
            return expr
        self._error_current("Expected expression")

    def _parse_identifier_expression(self) -> Expression:
        parts = [self._parse_identifier()]
        while self._match(TokenType.DOT):
            if self._match(TokenType.STAR):
                return StarExpr(table=".".join(parts))
            parts.append(self._parse_identifier())

        if self._match(TokenType.LPAREN):
            return self._finish_function_call(".".join(parts))

        if len(parts) == 1:
            return ColumnRef(name=parts[0])
        return ColumnRef(name=parts[-1], table=".".join(parts[:-1]))

    def _finish_function_call(self, name: str) -> FunctionCall | AggregateExpr:
        distinct = self._match(TokenType.DISTINCT) is not None
        args: list[Expression] = []
        if not self._check(TokenType.RPAREN):
            args = self._parse_expression_list()
        self._expect(TokenType.RPAREN)

        upper_name = name.upper()
        if upper_name in _AGGREGATE_FUNCTIONS:
            if len(args) > 1:
                self._error_current(f"Aggregate {upper_name} accepts one argument")
            return AggregateExpr(
                function=upper_name,
                arg=args[0] if args else None,
                distinct=distinct,
            )
        return FunctionCall(name=name, args=args, distinct=distinct)

    def _parse_exists(self) -> ExistsExpr:
        self._expect(TokenType.EXISTS)
        self._expect(TokenType.LPAREN)
        query = self._parse_select()
        self._expect(TokenType.RPAREN)
        return ExistsExpr(subquery=SubqueryExpr(query=query))

    def _parse_case(self) -> CaseExpr:
        self._expect(TokenType.CASE)
        operand = None
        if not self._check(TokenType.WHEN):
            operand = self._parse_expression()

        when_clauses: list[WhenClause] = []
        while self._match(TokenType.WHEN):
            condition = self._parse_expression()
            self._expect(TokenType.THEN)
            result = self._parse_expression()
            when_clauses.append(WhenClause(condition=condition, result=result))

        if not when_clauses:
            self._error_current("CASE requires at least one WHEN clause")

        else_expr = None
        if self._match(TokenType.ELSE):
            else_expr = self._parse_expression()
        self._expect(TokenType.END)
        return CaseExpr(operand=operand, when_clauses=when_clauses, else_expr=else_expr)

    def _finish_window_expr(self, function: FunctionCall | AggregateExpr) -> WindowExpr:
        self._expect(TokenType.LPAREN)
        partition_by: list[Expression] = []
        order_by = None
        frame = None

        if self._match(TokenType.PARTITION):
            self._expect(TokenType.BY)
            partition_by = self._parse_expression_list()

        if self._match_order_by():
            order_by = self._parse_order_by_items()

        if self._check(TokenType.ROWS, TokenType.RANGE):
            frame = self._parse_window_frame()

        self._expect(TokenType.RPAREN)
        return WindowExpr(
            function=function,
            partition_by=partition_by,
            order_by=order_by,
            frame=frame,
        )

    def _parse_window_frame(self) -> WindowFrame:
        mode = self._advance().type.name
        if self._match(TokenType.BETWEEN):
            start = self._parse_frame_bound()
            self._expect(TokenType.AND)
            end = self._parse_frame_bound()
            return WindowFrame(mode=mode, start=start, end=end)
        return WindowFrame(mode=mode, start=self._parse_frame_bound(), end=None)

    def _parse_frame_bound(self) -> FrameBound:
        if self._match(TokenType.UNBOUNDED):
            if self._match(TokenType.PRECEDING):
                return FrameBound(bound_type="UNBOUNDED PRECEDING")
            if self._match(TokenType.FOLLOWING):
                return FrameBound(bound_type="UNBOUNDED FOLLOWING")
            self._error_current("Expected PRECEDING or FOLLOWING after UNBOUNDED")
        if self._match(TokenType.CURRENT):
            self._expect(TokenType.ROW)
            return FrameBound(bound_type="CURRENT ROW")
        offset = self._parse_integer_literal("window frame")
        if self._match(TokenType.PRECEDING):
            return FrameBound(bound_type="N PRECEDING", offset=offset)
        if self._match(TokenType.FOLLOWING):
            return FrameBound(bound_type="N FOLLOWING", offset=offset)
        self._error_current("Expected PRECEDING or FOLLOWING in frame bound")

    def _parse_table_ref(self, allow_alias: bool = True) -> TableRef:
        parts = [self._parse_identifier()]
        while self._match(TokenType.DOT):
            parts.append(self._parse_identifier())

        schema = ".".join(parts[:-1]) if len(parts) > 1 else None
        table = TableRef(name=parts[-1], schema=schema)

        if allow_alias:
            alias = self._parse_optional_table_alias()
            if alias is not None:
                table.alias = alias
        return table

    def _parse_optional_alias(self) -> str | None:
        if self._match(TokenType.AS):
            return self._parse_identifier()
        if self._check(TokenType.IDENTIFIER) and self._current().type not in _CLAUSE_STARTS:
            return self._advance().value
        return None

    def _parse_optional_table_alias(self) -> str | None:
        if self._match(TokenType.AS):
            return self._parse_identifier()
        if self._check(TokenType.IDENTIFIER) and not self._identifier_value_is("IF"):
            return self._advance().value
        return None

    def _parse_expression_list(self) -> list[Expression]:
        items = [self._parse_expression()]
        while self._match(TokenType.COMMA):
            items.append(self._parse_expression())
        return items

    def _parse_order_by_items(self) -> list[OrderByItem]:
        items = []
        while True:
            expr = self._parse_expression()
            ascending = True
            if self._match(TokenType.ASC):
                ascending = True
            elif self._match(TokenType.DESC):
                ascending = False
            items.append(OrderByItem(expr=expr, ascending=ascending))
            if not self._match(TokenType.COMMA):
                break
        return items

    def _parse_identifier_list(self) -> list[str]:
        items = [self._parse_identifier()]
        while self._match(TokenType.COMMA):
            items.append(self._parse_identifier())
        return items

    def _parse_identifier_path(self) -> str:
        parts = [self._parse_identifier()]
        while self._match(TokenType.DOT):
            parts.append(self._parse_identifier())
        return ".".join(parts)

    def _parse_data_type(self) -> str:
        parts: list[str] = []
        paren_depth = 0
        while not self._check(TokenType.EOF):
            if paren_depth == 0 and (
                self._check(TokenType.COMMA, TokenType.RPAREN)
                or self._is_column_constraint_start(self._current())
            ):
                break
            tok = self._advance()
            if tok.type == TokenType.LPAREN:
                paren_depth += 1
            elif tok.type == TokenType.RPAREN:
                paren_depth -= 1
                if paren_depth < 0:
                    self._error(tok, "Unexpected ')' in data type")
            parts.append(tok.value)

        if not parts:
            self._error_current("Expected column data type")
        if paren_depth != 0:
            self._error_current("Unclosed parenthesis in data type")
        return self._format_type_parts(parts)

    def _parse_integer_literal(self, context: str) -> int:
        tok = self._expect(TokenType.NUMBER)
        try:
            return int(tok.value)
        except ValueError:
            self._error(tok, f"Expected integer literal for {context}")

    def _match_group_by(self) -> bool:
        if self._match(TokenType.GROUP_BY):
            return True
        if self._match(TokenType.GROUP):
            self._expect(TokenType.BY)
            return True
        return False

    def _match_order_by(self) -> bool:
        if self._match(TokenType.ORDER_BY):
            return True
        if self._match(TokenType.ORDER):
            self._expect(TokenType.BY)
            return True
        return False

    def _expect_operator(self, operator: str) -> Token:
        tok = self._current()
        if tok.type == TokenType.OPERATOR and tok.value == operator:
            return self._advance()
        self._error_current(f"Expected operator {operator!r}")

    def _parse_identifier(self) -> str:
        tok = self._current()
        if tok.type != TokenType.IDENTIFIER:
            self._error_current("Expected identifier")
        return self._advance().value

    def _expect_identifier(self, value: str) -> Token:
        tok = self._current()
        if tok.type == TokenType.IDENTIFIER and tok.value.upper() == value.upper():
            return self._advance()
        self._error_current(f"Expected {value}")

    def _match_identifier(self, value: str) -> bool:
        if self._current().type == TokenType.IDENTIFIER and self._current().value.upper() == value.upper():
            self._advance()
            return True
        return False

    def _identifier_value_is(self, value: str) -> bool:
        return self._current().type == TokenType.IDENTIFIER and self._current().value.upper() == value.upper()

    def _is_column_constraint_start(self, tok: Token) -> bool:
        if tok.type in {TokenType.NOT, TokenType.NULL}:
            return True
        return tok.type == TokenType.IDENTIFIER and tok.value.upper() in {"PRIMARY", "DEFAULT"}

    def _format_type_parts(self, parts: list[str]) -> str:
        result = ""
        previous = ""
        for part in parts:
            if part == "(":
                result += part
            elif part == ")":
                result += part
            elif previous == "(":
                result += part
            elif not result:
                result = part
            else:
                result += f" {part}"
            previous = part
        return result

    def _expect(self, token_type: TokenType) -> Token:
        tok = self._current()
        if tok.type != token_type:
            self._error(tok, f"Expected {token_type.name}, got {tok.type.name} ({tok.value!r})")
        return self._advance()

    def _match(self, *types: TokenType) -> Token | None:
        if self._check(*types):
            return self._advance()
        return None

    def _check(self, *types: TokenType) -> bool:
        return self._current().type in types

    def _current(self) -> Token:
        return self.tokens.current()

    def _advance(self) -> Token:
        return self.tokens.advance()

    def _error_current(self, message: str) -> None:
        self._error(self._current(), message)

    def _error(self, token: Token, message: str) -> None:
        raise ParserError(f"{message} at L{token.line}:{token.col}")


def parse(query: str) -> Statement:
    """Parse a SQL query string into an AST statement."""
    return Parser(query).parse_statement()

